mapper.select:
SELECT m.id, m.message_title, m.message_type, m.sender_id, u.nickname AS sender_name, m.priority, mu.read_status, m.create_time FROM sys_message m LEFT JOIN sys_message_user mu ON m.id = mu.message_id AND mu.del_flag = '0' LEFT JOIN sys_user u ON m.sender_id = u.id WHERE m.del_flag = '0' AND mu.receiver_id = #{receiverId} AND m.status = '0'
AND m.message_title LIKE CONCAT('%', #{query.messageTitle}, '%')
AND m.message_type = #{query.messageType}
AND mu.read_status = #{query.readStatus}
AND m.sender_id = #{query.senderId}
AND m.priority = #{query.priority}
ORDER BY m.priority DESC, m.create_time DESC

SELECT m.id, m.message_title, m.message_type, m.priority, m.create_time, COUNT(mu.id) AS receiver_count, SUM(CASE WHEN mu.read_status = '1' THEN 1 ELSE 0 END) AS read_count FROM sys_message m LEFT JOIN sys_message_user mu ON m.id = mu.message_id AND mu.del_flag = '0' WHERE m.del_flag = '0' AND m.sender_id = #{senderId}
AND m.message_title LIKE CONCAT('%', #{query.messageTitle}, '%')
AND m.message_type = #{query.messageType}
AND m.priority = #{query.priority}
GROUP BY m.id, m.message_title, m.message_type, m.priority, m.create_time ORDER BY m.create_time DESC
